```html
<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>贪吃蛇游戏</title>
    <style>
        body {
            display: flex;
            justify-content: center;
            align-items: center;
            height: 100vh;
            margin: 0;
            background-color: #f4f4f9;
        }
        canvas {
            border: 1px solid #dfe1e5;
        }
    </style>
</head>
<body>
    <canvas id="gameCanvas" width="400" height="400"></canvas>
    <script>
        const canvas = document.getElementById('gameCanvas');
        const ctx = canvas.getContext('2d');

        let snake = [{ x: 200, y: 200 }];
        let direction = { x: 10, y: 0 };
        let food = { x: Math.floor(Math.random() * 39) * 10, y: Math.floor(Math.random() * 39) * 10 };
        let gameOver = false;

        function drawRect(x, y, width, height, color) {
            ctx.fillStyle = color;
            ctx.fillRect(x, y, width, height);
        }

        function drawSnake() {
            snake.forEach(segment => {
                drawRect(segment.x, segment.y, 10, 10, 'green');
            });
        }

        function drawFood() {
            drawRect(food.x, food.y, 10, 10, 'red');
        }

        function updateGame() {
            if (gameOver) return;

            const head = { x: snake[0].x + direction.x, y: snake[0].y + direction.y };

            // 检查碰撞
            if (
                head.x < 0 || head.x >= canvas.width ||
                head.y < 0 || head.y >= canvas.height ||
                snake.some(segment => segment.x === head.x && segment.y === head.y)
            ) {
                gameOver = true;
                alert('游戏结束！按F5刷新重试。');
                return;
            }

            if (head.x === food.x && head.y === food.y) {
                snake.push({ ...snake[snake.length - 1] });
                food = { x: Math.floor(Math.random() * 39) * 10, y: Math.floor(Math.random() * 39) * 10 };
            } else {
                snake.shift();
            }

            snake.unshift(head);
        }

        function gameLoop() {
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            drawFood();
            drawSnake();

            updateGame();

            requestAnimationFrame(gameLoop);
        }

        document.addEventListener('keydown', event => {
            switch (event.key) {
                case 'ArrowUp':
                    if (direction.y === 0) direction = { x: 0, y: -10 };
                    break;
                case 'ArrowDown':
                    if (direction.y === 0) direction = { x: 0, y: 10 };
                    break;
                case 'ArrowLeft':
                    if (direction.x === 0) direction = { x: -10, y: 0 };
                    break;
                case 'ArrowRight':
                    if (direction.x === 0) direction = { x: 10, y: 0 };
                    break;
            }
        });

        gameLoop();
    </script>
</body>
</html>
```

